  "code": "import random
import time

class GameState:
    def __init__(self):
        self.player_hp = 100
        self.player_attack = 15
        self.inventory = []
        self.game_over = False

    def take_damage(self, amount):
        self.player_hp -= amount
        print(f"You took {amount} damage! HP: {self.player_hp}/{100}")
        if self.player_hp <= 0:
            self.game_over = True

class Enemy:
    def __init__(self, name, hp, attack):
        self.name = name
        self.hp = hp
        self.attack = attack

    def is_alive(self):
        return self.hp > 0

def battle(player, enemy):
    print(f"\n--- A wild {enemy.name} appears! ---")

    while enemy.is_alive() and not player.game_over:
        print(f"\n{enemy.name} HP: {enemy.hp} | Your HP: {player.player_hp}")
        action = input("Choose action: (A)ttack, (H)eal, (R)un: ").lower()

        if action == 'a':
            dmg = random.randint(player.player_attack - 5, player.player_attack + 5)
            enemy.hp -= dmg
            print(f"You hit the {enemy.name} for {dmg} damage!")
        elif action == 'h':
            if "Health Potion" in player.inventory:
                player.player_hp = min(100, player.player_hp + 30)
                player.inventory.remove("Health Potion")
                print("You used a Health Potion! Recovered 30 HP.")
            else:
                print("No potions left!")
                continue
        elif action == 'r':
            if random.random() > 0.5:
                print("You successfully escaped!")
                return False
            else:
                print("Failed to escape!")
        else:
            print("Invalid choice!")
            continue

        if enemy.is_alive():
            enemy_dmg = random.randint(enemy.attack - 3, enemy.attack + 3)
            player.take_damage(enemy_dmg)

    if not player.game_over:
        print(f"Victory! You defeated the {enemy.name}!")
        return True
    return False

def main():
    print("Welcome to the Weaver's Dungeon!")
    player = GameState()
    player.inventory.append("Health Potion")

    enemies = [
        Enemy("Slime", 30, 5),
        Enemy("Goblin", 50, 10),
        Enemy("Orc", 80, 15),
        Enemy("Shadow Dragon", 150, 25)
    ]

    for enemy in enemies:
        if player.game_over:
            break

        success = battle(player, enemy)
        if not success and player.game_over:
            print("\nGAME OVER. You perished in the dungeon.")
            break

        if success:
            print("You find a Health Potion on the ground!")
            player.inventory.append("Health Potion")
            time.sleep(1)

    if not player.game_over:
        print("\nCONGRATULATIONS! You have conquered the dungeon!")

if __name__ == "__main__":
    main()",
